 */
public static int computeUTF8Size(final CharSequence str, final int index, final int len) {
    if (str == null) {
        throw new IllegalArgumentException("Input string cannot be null");
    }
    if (index < 0 || len < 0 || index + len > str.length()) {
        throw new IndexOutOfBoundsException("Index or length is out of bounds");
    }
    String substring = str.subSequence(index, index + len).toString();
    return substring.getBytes(StandardCharsets.UTF_8).length;
}

/**
 * 计算从指定 {@code index} 开始，具有指定 {@code length} 长度的 UTF-8 字符串的大小。
 */
public static int computeUTF8Size(final CharSequence str, final int index, final int len) {
    if (str == null) {
        throw new IllegalArgumentException("Input string cannot be null");
    }
    if (index < 0 || len < 0 || index + len > str.length()) {
        throw new IndexOutOfBoundsException("Index or length is out of bounds");
    }
    int size = 0;
    for (int i = index; i < index + len; i++) {
        char c = str.charAt(i);
        if (c <= 0x7F) {
            // 1 byte for ASCII
            size += 1;
        } else if (c <= 0x7FF) {
            // 2 bytes for characters in range 0x80 to 0x7FF
            size += 2;
        } else if (c >= 0xD800 && c <= 0xDFFF) {
            // Surrogate pair
            if (i + 1 < index + len) {
                char next = str.charAt(i + 1);
                if (next >= 0xDC00 && next <= 0xDFFF) {
                    // 4 bytes for surrogate pairs
                    size += 4;
                    // Skip the next character
                    i++;
                } else {
                    throw new IllegalArgumentException("Invalid surrogate pair");
                }
            } else {
                throw new IllegalArgumentException("Invalid surrogate pair");
            }
        } else {
            // 3 bytes for characters in range 0x800 to 0xFFFF
            size += 3;
        }
    }
    return size;
}

