/**
 * 从流中读取原始 Varint。
 */
public long readRawVarint64() throws IOException {
    long result = 0;
    int shift = 0;
    while (true) {
        int b = input.read();
        if (b == -1) {
            throw new IOException("End of stream reached");
        }
        result |= (long) (b & 0x7F) << shift;
        if ((b & 0x80) == 0) {
            return result;
        }
        shift += 7;
        if (shift >= 64) {
            throw new IOException("Varint is too long");
        }
    }
}

