/**
 * 将 {@link LinkedBuffer} 的内容写入 {@link DataOutput}。
 * @return 缓冲区的总内容大小。
 */
public static int writeTo(final DataOutput out, LinkedBuffer node) throws IOException {
    int totalSize = 0;
    LinkedBuffer current = node;
    while (current != null) {
        // Assuming LinkedBuffer has a method to get its data
        byte[] data = current.getData();
        out.write(data);
        totalSize += data.length;
        // Assuming LinkedBuffer has a method to get the next node
        current = current.getNext();
    }
    return totalSize;
}

