 * @return 子字符串 {@code sub} 在字符串 {@code str} 中出现的次数。
 */
public static int countOccurrencesOf(String str, String sub) {
    if (str == null || sub == null || str.isEmpty() || sub.isEmpty()) {
        return 0;
    }
    int count = 0;
    int index = 0;
    while ((index = str.indexOf(sub, index)) != -1) {
        count++;
        index += sub.length();
    }
    return count;
}

