 * @param elements 需弹出的抽象类型数量。
 */
private void pop(final int elements) {
    if (elements < 0) {
        throw new IllegalArgumentException("Number of elements to pop must be non-negative.");
    }
    for (int i = 0; i < elements; i++) {
        if (!stack.isEmpty()) {
            stack.pop();
        } else {
            // Stop if the stack is empty
            break;
        }
    }
}

