/**
 * 原子性地将所有 {@link ListNode ListNodes} 从 {@code list} 移动到此列表，
 * 就像每个节点都是通过 {@link #removeListNode(ListNodeImpl)} 从 {@code list} 中移除的，
 * 然后依次通过 {@link #addListNode(ListNodeImpl)} 添加到此列表中。
 */
private void moveAllListNodes(DoublyLinkedList<E> list) {
    if (list.head == null) {
        // Nothing to move
        return;
    }
    ListNode<E> current = list.head;
    while (current != null) {
        // Store next node
        ListNode<E> nextNode = current.next;
        // Remove from the source list
        removeListNode(current);
        // Add to this list
        addListNode(current);
        // Move to the next node
        current = nextNode;
    }
    // Clear the source list
    list.head = null;
    list.tail = null;
}

