 * @param nameStart 要缩写的名称起始位置。
 */
public void abbreviate(final int nameStart, final StringBuffer buf) {
    if (nameStart < 0 || buf == null) {
        throw new IllegalArgumentException("Invalid parameters");
    }
    String name = buf.toString();
    if (nameStart >= name.length()) {
        // No abbreviation possible
        return;
    }
    StringBuilder abbreviation = new StringBuilder();
    // Add the first character of the name
    abbreviation.append(name.charAt(nameStart));
    for (int i = nameStart + 1; i < name.length(); i++) {
        if (Character.isUpperCase(name.charAt(i))) {
            // Add uppercase letters
            abbreviation.append(name.charAt(i));
        }
    }
    // Clear the buffer
    buf.setLength(0);
    // Append the abbreviation
    buf.append(abbreviation);
}

