/**
 * 检查由给定的 <code>vertices</code> 诱导的 <code>graph</code> 的子图是否为完全图，即一个团。
 * @param graph 图。
 * @param vertices 用于诱导子图的顶点。
 * @return 如果诱导的子图是一个团，则返回真。
 */
private static <V, E> boolean isClique(Graph<V, E> graph, Set<V> vertices) {
    int vertexCount = vertices.size();
    if (vertexCount < 2) {
        // A single vertex or empty set is trivially a clique
        return true;
    }
    // Check if every pair of vertices in the set is connected
    for (V v1 : vertices) {
        for (V v2 : vertices) {
            if (!v1.equals(v2) && !graph.containsEdge(v1, v2)) {
                // Found a pair that is not connected
                return false;
            }
        }
    }
    // All pairs are connected
    return true;
}

/**
 * 检查由给定的 <code>vertices</code> 诱导的 <code>graph</code> 的子图是否为完全图，即一个团。
 * @param graph 图。
 * @param vertices 用于诱导子图的顶点。
 * @return 如果诱导的子图是一个团，则返回真。
 */
private static <V, E> boolean isClique(Graph<V, E> graph, Set<V> vertices) {
    if (vertices.size() < 2) {
        // A single vertex or empty set is trivially a clique
        return true;
    }
    // n(n-1)/2
    int expectedEdges = vertices.size() * (vertices.size() - 1) / 2;
    int actualEdges = 0;
    for (V vertex : vertices) {
        Set<V> neighbors = graph.getNeighbors(vertex);
        for (V neighbor : neighbors) {
            if (vertices.contains(neighbor)) {
                actualEdges++;
            }
        }
    }
    // Each edge is counted twice (u-v and v-u), so divide by 2
    actualEdges /= 2;
    return actualEdges == expectedEdges;
}

/**
 * 检查由给定的 <code>vertices</code> 诱导的 <code>graph</code> 的子图是否为完全图，即一个团。
 * @param graph 图。
